import { useEffect, useState } from "react";
import ListOnLesson from "../../Components/Lists/ListOnLesson";
import MainBtns from "../../Components/Buttons/MainBtns";




function LearnCoursePage() {
  const [materials, setMaterials] = useState([]);
  const text = 
  `Для решения этой задачи стоит применить один трюк. Если карта лежит рубашкой вверх, сопоставим ей 0, если рубашкой вниз, то 1. Запишем эти цифры слева  направо  начиная с цифры, соответствующей верхней карте, мы получим некоторое натуральное число. При каждом переворачивании пачки карт это число уменьшается: 1, соответствующая верхней карте в пачке, заменяется 0, а цифры в более старших разрядах не меняются. То есть в этой задаче инвариантом выступает само число, которое постоянно уменьшается. Но натуральное число не может уменьшаться бесконечно, поэтому когда-нибудь переворачивания прекратятся. Это и значит, что все карты легли рубашкой вверх.

Стоит заметить, что для упрощения интерпретации задачи и её дальнейшего решения, мы её немного причесали, сделав более аккуратной и удобной для работы. А теперь перейдём к самостоятельному решению задач.
`;
  
  
  useEffect(() => {
    fetch(`/Files/Tests/materialOfCourse.json`, { cache: "no-store" })
      .then(res => {
        if (!res.ok) throw new Error("Ресурс не найден");
        return res.json();
      }).then(datas => setMaterials(datas))


    }, []);

  return (
    <div className="learn-page">

      <div className="left-panel">
        <ul>
          {materials.map((item,index)=> (
            <li key={index}>
              <ListOnLesson data={item.materialOfCourse}/>
            </li>
          ))}
        </ul>
      </div>



      <div className="main-info">
        <div style={{ marginBottom:"25px", fontSize:"20px"}}>
          <span>
            {text}
          </span>

        </div>
        <div className="bottom-area" style={{backgroundColor:"green"}}>
          <MainBtns Style={"null-btn"} Text={"Далее"}/>
        </div>
      </div>
    </div>
  );
}

export default LearnCoursePage;
